using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Collect all errors
var errors = new List<(string project, string file, int line, int col, string code, string message, string subcategory)>();
var warnings = new List<(string project, string file, int line, int col, string code, string message)>();

build.VisitAllChildren<Error>(e =>
{
    var proj = "";
    var parent = e.Parent;
    while (parent != null)
    {
        if (parent is Project p) { proj = p.Name; break; }
        parent = (parent as TreeNode)?.Parent;
    }
    errors.Add((proj, e.File ?? "", e.LineNumber, e.ColumnNumber, e.Code ?? "", e.Text ?? "", e.Subcategory ?? ""));
});

build.VisitAllChildren<Warning>(w =>
{
    var proj = "";
    var parent = w.Parent;
    while (parent != null)
    {
        if (parent is Project p) { proj = p.Name; break; }
        parent = (parent as TreeNode)?.Parent;
    }
    warnings.Add((proj, w.File ?? "", w.LineNumber, w.ColumnNumber, w.Code ?? "", w.Text ?? ""));
});

Console.WriteLine("=== BUILD SUCCEEDED: " + build.Succeeded + " ===");
Console.WriteLine();

Console.WriteLine($"=== ERRORS ({errors.Count}) ===");
foreach (var e in errors)
{
    Console.WriteLine($"  Project: {e.project}");
    Console.WriteLine($"  File:    {e.file}({e.line},{e.col})");
    Console.WriteLine($"  Code:    {e.code}");
    Console.WriteLine($"  Message: {e.message}");
    Console.WriteLine();
}

Console.WriteLine($"=== WARNINGS ({warnings.Count}) ===");
foreach (var w in warnings)
{
    Console.WriteLine($"  Project: {w.project}");
    Console.WriteLine($"  File:    {w.file}({w.line},{w.col})");
    Console.WriteLine($"  Code:    {w.code}");
    Console.WriteLine($"  Message: {w.message}");
    Console.WriteLine();
}

// Print project dependency graph info
Console.WriteLine("=== PROJECT STRUCTURE ===");
build.VisitAllChildren<Project>(p =>
{
    Console.WriteLine($"  Project: {p.Name} | Result: {(p.Succeeded ? "OK" : "FAILED")}");
});
