using System;
using System.Collections.Generic;
using System.Linq;
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Extract project references to understand dependency graph
Console.WriteLine("=== PROJECT REFERENCES ===");
build.VisitAllChildren<AddItem>(ai =>
{
    if (ai.Name == "ProjectReference")
    {
        var proj = "";
        var parent = ai.Parent;
        while (parent != null)
        {
            if (parent is Project p) { proj = p.Name; break; }
            parent = (parent as TreeNode)?.Parent;
        }
        foreach (var child in ai.Children.OfType<Item>())
        {
            Console.WriteLine($"  {proj} -> {child.Text}");
        }
    }
});

// Look at MSBuild error/message for project build failure propagation
Console.WriteLine();
Console.WriteLine("=== MSBUILD ERRORS (including MSB codes) ===");
build.VisitAllChildren<Message>(m =>
{
    if (m.Text != null && (m.Text.Contains("MSB") || m.Text.Contains("error")) && m.Text.Length < 300)
    {
        var proj = "";
        var parent = m.Parent;
        while (parent != null)
        {
            if (parent is Project p) { proj = p.Name; break; }
            parent = (parent as TreeNode)?.Parent;
        }
        // Only show interesting messages
        if (m.Text.Contains("error") || m.Text.Contains("fail"))
            Console.WriteLine($"  [{proj}] {m.Text}");
    }
});

// Check which projects actually failed to build  
Console.WriteLine();
Console.WriteLine("=== PROJECTS WITH BUILD FAILURES ===");
build.VisitAllChildren<Target>(t =>
{
    if (t.Name == "CoreCompile")
    {
        var proj = "";
        var parent = t.Parent;
        while (parent != null)
        {
            if (parent is Project p) { proj = p.Name; break; }
            parent = (parent as TreeNode)?.Parent;
        }
        var hasError = false;
        t.VisitAllChildren<Error>(e => hasError = true);
        if (hasError)
            Console.WriteLine($"  {proj} - CoreCompile FAILED");
    }
});

// Extract source file contents from the binlog  
Console.WriteLine();
Console.WriteLine("=== EXAMINING SOURCE FILES ===");
build.VisitAllChildren<Item>(item =>
{
    if (item.Text != null && item.Text.Contains("UserService.cs"))
        Console.WriteLine($"  Item: {item.Text}");
});

// Check for project-level failures
Console.WriteLine();
Console.WriteLine("=== CHECKING FOR CASCADING MSB3202/MSB4181 ===");
build.VisitAllChildren<Error>(e =>
{
    if (e.Code != null && (e.Code.StartsWith("MSB") || e.Code == "CS0006"))
    {
        var proj = "";
        var parent = e.Parent;
        while (parent != null)
        {
            if (parent is Project p) { proj = p.Name; break; }
            parent = (parent as TreeNode)?.Parent;
        }
        Console.WriteLine($"  [{proj}] {e.Code}: {e.Text}");
    }
});
